1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const LOYALTY_RATE = 0.2;
8	const FOLLOW_UP_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
14	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const INSURANCE_VALUE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	type Item = {
35	  type: string;
36	  material?: string;
37	  enchantment?: number;
38	  cursed?: boolean;
39	};
40	type Damage = { itemType: string; amount: number };
41	type Incident = { cause: string; damages: Damage[] };
42	type QuoteStep = { op: "quote"; items: Item[] };
43	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
44	type Step = QuoteStep | ClaimStep;
45	type Customer = { yearsWithMHPCO: number };
46	type Scenario = { customer: Customer; steps: Step[] };
47	type QuoteResult = { premium: number };
48	type ClaimResult = { payout: number; remainingCap: number };
49	type StepResult = QuoteResult | ClaimResult;
50	type ScenarioOutput = { results: StepResult[] };
51	
52	type Policy = { items: Item[]; remainingCap: number };
53	
54	const groupCountsByType = (items: Item[]): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const { type } of items) {
57	    counts.set(type, (counts.get(type) ?? 0) + 1);
58	  }
59	  return counts;
60	};
61	
62	const basePremiumForGroup = (type: string, count: number): number => {
63	  if (!(type in BASE_PREMIUM)) {
64	    throw new Error(`unknown item type: ${type}`);
65	  }
66	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
67	  return count * BASE_PREMIUM[type];
68	};
69	
70	const basePremiumFor = (items: Item[]): number =>
71	  Array.from(groupCountsByType(items)).reduce(
72	    (total, [type, count]) => total + basePremiumForGroup(type, count),
73	    0,
74	  );
75	
76	const curseSurchargeFor = (item: Item): number =>
77	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_RATE : 0;
78	
79	const highEnchantmentSurchargeFor = (item: Item): number =>
80	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
81	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE
82	    : 0;
83	
84	const ITEM_SURCHARGES: Array<(item: Item) => number> = [
85	  curseSurchargeFor,
86	  highEnchantmentSurchargeFor,
87	];
88	
89	const surchargesForItem = (item: Item): number =>
90	  ITEM_SURCHARGES.reduce((sum, surcharge) => sum + surcharge(item), 0);
91	
92	const itemSurchargesFor = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
94	
95	const firstInsuranceSurchargeFor = (basePremium: number): number =>
96	  basePremium * FIRST_INSURANCE_RATE;
97	
98	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
99	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
100	    ? basePremium * LOYALTY_RATE
101	    : 0;
102	
103	const followUpDiscountFor = (basePremium: number, isFollowUp: boolean): number =>
104	  isFollowUp ? basePremium * FOLLOW_UP_RATE : 0;
105	
106	const premiumFor = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
107	  const basePremium = basePremiumFor(items);
108	  const surcharges =
109	    itemSurchargesFor(items) + firstInsuranceSurchargeFor(basePremium);
110	  const discounts =
111	    loyaltyDiscountFor(basePremium, customer) +
112	    followUpDiscountFor(basePremium, isFollowUp);
113	  return Math.ceil(basePremium + surcharges - discounts + PROCESSING_FEE);
114	};
115	
116	const quoteStep = (
117	  { items }: QuoteStep,
118	  customer: Customer,
119	  isFollowUp: boolean,
120	): QuoteResult => ({
121	  premium: premiumFor(items, customer, isFollowUp),
122	});
123	
124	const insuranceSumFor = (items: Item[]): number =>
125	  items.reduce((sum, { type }) => sum + INSURANCE_VALUE[type], 0);
126	
127	const reimbursableAmountFor = (item: Item, damageAmount: number): number =>
128	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
129	    ? damageAmount * HIGH_ENCHANTMENT_CLAIM_RATE
130	    : damageAmount;
131	
132	const insuredItemFor = (damage: Damage, policy: Policy): Item =>
133	  policy.items.find((item) => item.type === damage.itemType)!;
134	
135	const payoutForDamage = (damage: Damage, policy: Policy): number => {
136	  const reimbursable = reimbursableAmountFor(insuredItemFor(damage, policy), damage.amount);
137	  return Math.max(0, reimbursable - DEDUCTIBLE);
138	};
139	
140	const validateDamages = (damages: Damage[], policy: Policy): void => {
141	  const insuredCounts = groupCountsByType(policy.items);
142	  const damageCounts = new Map<string, number>();
143	  for (const { itemType } of damages) {
144	    damageCounts.set(itemType, (damageCounts.get(itemType) ?? 0) + 1);
145	  }
146	  for (const [type, count] of damageCounts) {
147	    if (count > (insuredCounts.get(type) ?? 0)) {
148	      throw new Error(`claim references more ${type} items than insured`);
149	    }
150	  }
151	};
152	
153	const claimStep = (
154	  { policy: policyIndex, incident }: ClaimStep,
155	  policies: Policy[],
156	): ClaimResult => {
157	  const policy = policies[policyIndex];
158	  validateDamages(incident.damages, policy);
159	  const grossPayout = incident.damages.reduce(
160	    (sum, damage) => sum + payoutForDamage(damage, policy),
161	    0,
162	  );
163	  const payout = Math.min(grossPayout, policy.remainingCap);
164	  policy.remainingCap -= payout;
165	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
166	};
167	
168	const openPolicy = (items: Item[]): Policy => ({
169	  items,
170	  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
171	});
172	
173	const handleQuote = (
174	  step: QuoteStep,
175	  customer: Customer,
176	  policies: Policy[],
177	): QuoteResult => {
178	  const isFollowUp = policies.length > 0;
179	  policies.push(openPolicy(step.items));
180	  return quoteStep(step, customer, isFollowUp);
181	};
182	
183	export const runScenario = (input: Scenario): ScenarioOutput => {
184	  const policies: Policy[] = [];
185	  const results: StepResult[] = input.steps.map((step) =>
186	    step.op === "quote"
187	      ? handleQuote(step, input.customer, policies)
188	      : claimStep(step, policies),
189	  );
190	  return { results };
191	};
